import React, { useState, useEffect, useRef } from 'react';
import { devicesApi } from '../lib/api';

const Terminal = () => {
  const [tabs, setTabs] = useState([]);
  const [activeTab, setActiveTab] = useState(null);
  const [devices, setDevices] = useState([]);
  const [showDeviceList, setShowDeviceList] = useState(false);
  const [commandHistory, setCommandHistory] = useState([]);

  const terminalRef = useRef(null);
  const inputRef = useRef(null);

  useEffect(() => {
    loadDevices();
  }, []);

  const loadDevices = async () => {
    try {
      const response = await devicesApi.list();
      setDevices(response || []);
    } catch (error) {
      console.error('Error loading devices:', error);
    }
  };

  const openNewTab = (device) => {
    const existingTab = tabs.find(t => t.deviceId === device.id);
    if (existingTab) {
      setActiveTab(existingTab.id);
      setShowDeviceList(false);
      return;
    }

    const newTab = {
      id: Date.now(),
      deviceId: device.id,
      name: device.hostname || device.ip_address,
      ip: device.ip_address,
      port: device.port || 22,
      username: device.username || 'root',
      status: 'ready',
      output: [
        `\x1b[1;36m═══════════════════════════════════════════════════════════`,
        `\x1b[1;36m  LOR CGR Terminal - \x1b[1;33m${device.hostname}\x1b[0m`,
        `\x1b[1;36m  Host: \x1b[1;37m${device.ip_address}\x1b[0m  Porta: \x1b[1;37m${device.port || 22}\x1b[0m`,
        `\x1b[1;36m═══════════════════════════════════════════════════════════`,
        '',
        '\x1b[1;33m⚠ Modo Simulação - Conexão WebSocket não disponível\x1b[0m',
        '\x1b[90mDigite "help" para ver os comandos disponíveis\x1b[0m',
        '',
      ],
      input: '',
      history: []
    };

    setTabs(prev => [...prev, newTab]);
    setActiveTab(newTab.id);
    setShowDeviceList(false);
    appendOutput(newTab.id, `\x1b[1;32m${newTab.username}@${newTab.ip}\x1b[0m:\x1b[1;34m~\x1b[0m$ `);
  };

  const appendOutput = (tabId, text) => {
    setTabs(prev => prev.map(t => 
      t.id === tabId ? { ...t, output: [...t.output, text] } : t
    ));
    setTimeout(() => {
      const terminal = document.getElementById(`terminal-${tabId}`);
      if (terminal) terminal.scrollTop = terminal.scrollHeight;
    }, 10);
  };

  const sendCommand = (tabId, command) => {
    const tab = tabs.find(t => t.id === tabId);
    if (!tab || !command.trim()) return;

    setCommandHistory(prev => [...prev, command]);
    appendOutput(tabId, `\x1b[1;32m${tab.username}@${tab.ip}\x1b[0m:\x1b[1;34m~\x1b[0m$ ${command}`);

    simulateCommand(tabId, command, tab);
  };

  const simulateCommand = (tabId, command, tab) => {
    const cmd = command.trim().toLowerCase();
    const args = command.trim().split(' ').slice(1);

    setTimeout(() => {
      let output = '';

      switch (cmd.split(' ')[0]) {
        case 'ls':
          output = args.includes('-la') || args.includes('-l')
            ? 'total 48\ndrwxr-xr-x  5 root root 4096 Feb 15 10:00 .\ndrwxr-xr-x 20 root root 4096 Feb 10 09:00 ..\n-rw-r--r--  1 root root  220 Feb 10 09:00 .bash_logout\n-rw-r--r--  1 root root 3771 Feb 10 09:00 .bashrc'
            : 'Documents  Downloads  Scripts';
          break;
        case 'pwd':
          output = '/root';
          break;
        case 'whoami':
          output = tab.username;
          break;
        case 'hostname':
          output = tab.name.toLowerCase().replace(/\s+/g, '-');
          break;
        case 'date':
          output = new Date().toString();
          break;
        case 'uptime':
          output = ' 10:30:00 up 5 days, 12:34,  1 user,  load average: 0.15, 0.10, 0.05';
          break;
        case 'free':
          output = '              total        used        free      shared  buff/cache   available\nMem:        8192000     1234567     5432109       12345     1525324     6654321\nSwap:       2048000           0     2048000';
          break;
        case 'df':
          output = 'Filesystem     1K-blocks    Used Available Use% Mounted on\n/dev/sda1       51475068 8234512  40610472  17% /';
          break;
        case 'ip':
        case 'ifconfig':
          output = `eth0: flags=4163<UP,BROADCAST,RUNNING,MULTICAST>  mtu 1500\n        inet ${tab.ip}  netmask 255.255.255.0`;
          break;
        case 'ping':
          if (args[0]) {
            output = `PING ${args[0]}: 56 data bytes\n64 bytes: seq=0 ttl=56 time=12.345 ms\n64 bytes: seq=1 ttl=56 time=11.234 ms`;
          } else {
            output = 'ping: usage error: Destination address required';
          }
          break;
        case 'clear':
          setTabs(prev => prev.map(t => t.id === tabId ? { ...t, output: [] } : t));
          appendOutput(tabId, `\x1b[1;32m${tab.username}@${tab.ip}\x1b[0m:\x1b[1;34m~\x1b[0m$ `);
          return;
        case 'exit':
        case 'quit':
          closeTab(tabId);
          return;
        case 'help':
          output = 'Comandos disponíveis:\n  ls, pwd, whoami, hostname, date, uptime\n  free, df, ip/ifconfig, ping <host>\n  clear - limpar tela\n  exit - fechar terminal';
          break;
        case '':
          break;
        default:
          output = `bash: ${cmd.split(' ')[0]}: command not found`;
      }

      if (output) appendOutput(tabId, output);
      appendOutput(tabId, '');
      appendOutput(tabId, `\x1b[1;32m${tab.username}@${tab.ip}\x1b[0m:\x1b[1;34m~\x1b[0m$ `);
    }, 100);
  };

  const closeTab = (tabId, e) => {
    if (e) e.stopPropagation();
    setTabs(prev => {
      const newTabs = prev.filter(t => t.id !== tabId);
      if (activeTab === tabId && newTabs.length > 0) {
        setActiveTab(newTabs[newTabs.length - 1].id);
      } else if (newTabs.length === 0) {
        setActiveTab(null);
      }
      return newTabs;
    });
  };

  const handleKeyDown = (e, tabId) => {
    if (e.key === 'Enter') {
      sendCommand(tabId, e.target.value);
      e.target.value = '';
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      if (commandHistory.length > 0) {
        e.target.value = commandHistory[commandHistory.length - 1] || '';
      }
    } else if (e.ctrlKey && e.key === 'l') {
      e.preventDefault();
      setTabs(prev => prev.map(t => t.id === tabId ? { ...t, output: [] } : t));
    }
  };

  const renderOutput = (text) => {
    let formatted = text
      .replace(/\x1b\[1;36m/g, '<span class="text-cyan-400 font-bold">')
      .replace(/\x1b\[1;32m/g, '<span class="text-green-400 font-bold">')
      .replace(/\x1b\[1;33m/g, '<span class="text-yellow-400 font-bold">')
      .replace(/\x1b\[1;31m/g, '<span class="text-red-400 font-bold">')
      .replace(/\x1b\[1;34m/g, '<span class="text-blue-400 font-bold">')
      .replace(/\x1b\[1;37m/g, '<span class="text-white font-bold">')
      .replace(/\x1b\[90m/g, '<span class="text-gray-500">')
      .replace(/\x1b\[0m/g, '</span>');
    return <span dangerouslySetInnerHTML={{ __html: formatted }} />;
  };

  const currentTab = tabs.find(t => t.id === activeTab);

  return (
    <div className="flex flex-col h-[calc(100vh-150px)] bg-gray-900 rounded-lg overflow-hidden border border-gray-700">
      {/* Tabs Header */}
      <div className="flex items-center bg-gray-800 border-b border-gray-700">
        <div className="flex-1 flex overflow-x-auto">
          {tabs.map(tab => (
            <div
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex items-center space-x-2 px-4 py-3 cursor-pointer border-r border-gray-700 ${
                activeTab === tab.id ? 'bg-gray-900 text-white border-t-2 border-t-blue-500' : 'text-gray-400 hover:bg-gray-700'
              }`}
            >
              <span className="w-2 h-2 rounded-full bg-green-500"></span>
              <span className="text-sm font-medium">{tab.name}</span>
              <button onClick={(e) => closeTab(tab.id, e)} className="text-gray-500 hover:text-red-400 ml-2">✕</button>
            </div>
          ))}
        </div>
        <button onClick={() => setShowDeviceList(!showDeviceList)} className="px-4 py-3 text-gray-400 hover:text-white hover:bg-gray-700">
          ➕
        </button>
      </div>

      {/* Device List */}
      {showDeviceList && (
        <div className="absolute top-32 right-8 w-80 bg-gray-800 border border-gray-700 rounded-lg shadow-xl z-50 max-h-96 overflow-y-auto">
          <div className="p-3 border-b border-gray-700 flex items-center justify-between">
            <span className="text-white font-medium">Selecionar Dispositivo</span>
            <button onClick={() => setShowDeviceList(false)} className="text-gray-400 hover:text-white">✕</button>
          </div>
          <div className="p-2">
            {devices.length === 0 ? (
              <p className="text-gray-400 text-center py-4">Nenhum dispositivo</p>
            ) : (
              devices.map(device => (
                <button
                  key={device.id}
                  onClick={() => openNewTab(device)}
                  className="w-full flex items-center space-x-3 p-3 rounded-lg hover:bg-gray-700 text-left transition"
                >
                  <div className="w-2 h-2 rounded-full bg-green-500"></div>
                  <div className="flex-1">
                    <p className="text-white font-medium">{device.hostname}</p>
                    <p className="text-gray-400 text-sm">{device.ip_address}:{device.port || 22}</p>
                  </div>
                </button>
              ))
            )}
          </div>
        </div>
      )}

      {/* Terminal Content */}
      {currentTab ? (
        <div 
          className="flex-1 bg-gray-900 p-4 font-mono text-sm overflow-y-auto cursor-text"
          id={`terminal-${currentTab.id}`}
          onClick={() => inputRef.current?.focus()}
        >
          {currentTab.output.map((line, index) => (
            <div key={index} className="whitespace-pre-wrap">{renderOutput(line)}</div>
          ))}
          <input
            ref={inputRef}
            type="text"
            className="w-full bg-transparent text-green-400 outline-none font-mono"
            onKeyDown={(e) => handleKeyDown(e, currentTab.id)}
            autoFocus
          />
        </div>
      ) : (
        <div className="flex-1 flex flex-col items-center justify-center text-gray-400">
          <div className="text-6xl mb-4">💻</div>
          <h3 className="text-xl font-medium text-white mb-2">Terminal SSH</h3>
          <p className="text-gray-400 mb-4">Clique em + para abrir uma nova conexão</p>
          <button onClick={() => setShowDeviceList(true)} className="px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-lg">
            Nova Conexão
          </button>
        </div>
      )}

      {/* Status Bar */}
      {currentTab && (
        <div className="flex items-center justify-between px-4 py-2 bg-gray-800 border-t border-gray-700 text-xs text-gray-400">
          <div className="flex items-center space-x-4">
            <span>Host: <span className="text-white">{currentTab.ip}</span></span>
            <span>Porta: <span className="text-white">{currentTab.port}</span></span>
            <span>Usuário: <span className="text-white">{currentTab.username}</span></span>
          </div>
          <span className="px-2 py-1 rounded bg-orange-600/20 text-orange-400">🟠 Simulação</span>
        </div>
      )}
    </div>
  );
};

export default Terminal;
